1	import { MetadataExtractor } from './metadata';
2	import { DefuddleOptions, DefuddleResponse, MetaTagItem, DebugRemoval } from './types';
3	import { ExtractorRegistry } from './extractor-registry';
4	import type { ExtractorOptions } from './extractors/_base';
5	import { BaseExtractor } from './extractors/_base';
6	import {
7		MOBILE_WIDTH,
8		BLOCK_ELEMENTS_SELECTOR,
9		HIDDEN_EXACT_SKIP_SELECTOR,
10		ENTRY_POINT_ELEMENTS
11	} from './constants';
12	import { standardizeContent } from './standardize';
13	import { standardizeFootnotes } from './elements/footnotes';
14	import { standardizeCallouts } from './elements/callouts';
15	import { ContentScorer, ContentScore } from './removals/scoring';
16	import { findSmallImages, removeSmallImages } from './removals/small-images';
17	import { removeHiddenElements } from './removals/hidden';
18	import { removeBySelector } from './removals/selectors';
19	import { removeByContentPattern } from './removals/content-patterns';
20	import { removeMetadataBlock } from './removals/metadata-block';
21	import { getComputedStyle, textPreview, countWords, isSVGElement } from './utils';
22	import { parseHTML, serializeHTML, decodeHTMLEntities, isDangerousUrl, getClassName } from './utils/dom';
23	
24	interface StyleChange {
25		selector: string;
26		styles: string;
27	}
28	
29	/** Keys from extractor variables that map to top-level DefuddleResponse fields */
30	const STANDARD_VARIABLE_KEYS = new Set(['title', 'author', 'published', 'site', 'description', 'image', 'language']);
31	
32	
33	export class Defuddle {
34		private readonly doc: Document;
35		private options: DefuddleOptions;
36		private debug: boolean;
37		private _schemaOrgData: any = undefined;
38		private _schemaOrgExtracted = false;
39		private _metaTags: MetaTagItem[] | undefined;
40		private _metadata: any | undefined;
41		private _mobileStyles: StyleChange[] | undefined;
42		private _smallImages: Set<string> | undefined;
43		private _inExtractorPipelineRun = false;
44	
45		/**
46		 * Create a new Defuddle instance
47		 * @param doc - The document to parse
48		 * @param options - Options for parsing
49		 */
50		constructor(doc: Document, options: DefuddleOptions = {}) {
51			this.doc = doc;
52			this.options = options;
53			this.debug = options.debug || false;
54		}
55	
56		/**
57		 * Lazily extract and cache schema.org data. Must be called before
58		 * parse() strips script tags from the document.
59		 */
60		private getSchemaOrgData(): any {
61			if (!this._schemaOrgExtracted) {
62				this._schemaOrgData = this._extractSchemaOrgData(this.doc);
63				this._schemaOrgExtracted = true;
64			}
65			return this._schemaOrgData;
66		}
67	
68		/**
69		 * Parse the document and extract its main content
70		 */
71		parse(): DefuddleResponse {
72			// Normalize non-standard attribute casing (e.g. React SSR outputs
73			// "srcSet" instead of "srcset") before any image processing.
74			if (this.doc.body) {
75				this._normalizeAttributes(this.doc.body);
76				this._resolveNoscriptImages(this.doc.body);
77			}
78	
79			// Try first with default settings
80			let result = this.parseInternal();
81	
82			// If result has very little content, try again without clutter removal
83			if (result.wordCount < 200) {
84				this._log('Initial parse returned very little content, trying again');
85				const retryResult = this.parseInternal({
86					removePartialSelectors: false
87				});
88	
89				// Only use the retry if it produces significantly more content.
90				// A small increase likely means partial selectors correctly removed
91				// clutter (author blocks, related articles, etc.) from a short article.
92				// A large increase (2x+) suggests partial selectors were too aggressive.
93				if (retryResult.wordCount > result.wordCount * 2) {
94					this._log('Retry produced more content');
95					result = retryResult;
96				}
97			}
98	
99			// If still very little content, the page may be an index/listing page
100			// or a page that reveals content at runtime from a hidden wrapper.
101			// Retry once with hidden-element removal disabled.
102			if (result.wordCount < 50) {
103				this._log('Still very little content, retrying without hidden-element removal');
104				const hiddenRetry = this.parseInternal({
105					removeHiddenElements: false
106				});
107				if (hiddenRetry.wordCount > result.wordCount * 2) {
108					this._log('Hidden-element retry produced more content');
109					result = hiddenRetry;
110				}
111	
112				// Try targeting the largest hidden subtree directly to avoid body-level
113				// leftovers (e.g. FPS counters) when hidden content is the real article.
114				const hiddenSelector = this.findLargestHiddenContentSelector();
115				if (hiddenSelector) {
116					this._log('Retrying with hidden content selector:', hiddenSelector);
117					const hiddenSelectorRetry = this.parseInternal({
118						removeHiddenElements: false,
119						removePartialSelectors: false,
120						contentSelector: hiddenSelector
121					});
122					if (
123						hiddenSelectorRetry.wordCount > result.wordCount ||
124						(
125							hiddenSelectorRetry.wordCount > Math.max(20, result.wordCount * 0.7) &&
126							hiddenSelectorRetry.content.length < result.content.length
127						)
128					) {
129						this._log('Hidden-selector retry produced better focused content');
130						result = hiddenSelectorRetry;
131					}
132				}
133			}
134	
135			// If still very little content, the page may be an index/listing page
136			// where card elements were scored as non-content or removed by partial
137			// selectors (e.g. "post-preview"). Retry with both disabled.
138			if (result.wordCount < 50) {
139				this._log('Still very little content, retrying without scoring/partial selectors (possible index page)');
140				const indexRetry = this.parseInternal({
141					removeLowScoring: false,
142					removePartialSelectors: false,
143					removeContentPatterns: false
144				});
145				if (indexRetry.wordCount > result.wordCount) {
146					this._log('Index page retry produced more content');
147					result = indexRetry;
148				}
149			}
150	
151			// Strip dangerous elements from this.doc before any fallback paths
152			// that read from it. This must happen after parseInternal, which needs
153			// script tags for schema.org extraction, site-specific extractors, and math.
154			this._stripUnsafeElements();
155	
156			// If schema.org has text content that is significantly longer than what we
157			// extracted, the scorer likely picked the wrong element from a feed page.
158			// Use a 1.5x threshold to avoid triggering when the difference is small
159			// (e.g. just related-content link text removed).
160			const schemaText = this._getSchemaText(result.schemaOrgData);
161			if (schemaText && this.countHtmlWords(schemaText) > result.wordCount * 1.5) {
162				const bestMatch = this._findElementBySchemaText(this.doc.body, schemaText);
163				if (bestMatch) {
164					// Re-run the full pipeline with the schema-identified element as the
165					// content root so it benefits from the same cleanup as normal extraction.
166					const selector = this.getElementSelector(bestMatch);
167					this._log('Schema.org suggests a better content element, retrying with selector:', selector);
168					const schemaRetry = this.parseInternal({ contentSelector: selector });
169					result = schemaRetry;
170				} else {
171					this._log('Using schema.org text as content (DOM element not found)');
172					result.content = schemaText;
173					result.wordCount = this.countHtmlWords(schemaText);
174				}
175			}
176	
177			return result;
178		}
179	
180		/**
181		 * Extract text content from schema.org data (e.g. SocialMediaPosting, Article)
182		 */
183		private _getSchemaText(schemaOrgData: any, depth: number = 0): string {
184			if (!schemaOrgData || depth > 10) return '';
185	
186			const items = Array.isArray(schemaOrgData) ? schemaOrgData : [schemaOrgData];
187			for (const item of items) {
188				// Recurse into nested arrays
189				if (Array.isArray(item)) {
190					const found = this._getSchemaText(item, depth + 1);
191					if (found) return found;
192					continue;
193				}
194				if (item?.text && typeof item.text === 'string') {
195					return item.text;
196				}
197				if (item?.articleBody && typeof item.articleBody === 'string') {
198					return item.articleBody;
199				}
200				// Traverse @graph arrays (common in JSON-LD with multiple entities)
201				if (item?.['@graph'] && Array.isArray(item['@graph'])) {
202					const found = this._getSchemaText(item['@graph'], depth + 1);
203					if (found) return found;
204				}
205			}
206			return '';
207		}
208	
209		/**
210		 * Remove dangerous elements and attributes from this.doc.
211		 * Called after parseInternal so that extractors and schema extraction
212		 * can still read script tags they depend on.
213		 */
214		private _stripUnsafeElements(): void {
215			const body = this.doc.body;
216			if (!body) return;
217	
218			// Remove dangerous elements. Iframes are kept — same-origin policy
219			// isolates them, and they're widely used for legitimate media embeds.
220			// Dangerous iframe attributes (srcdoc, javascript: src) are stripped
221			// in the attribute pass below. Math scripts are preserved for LaTeX
222			// content (matching the EXACT_SELECTORS approach).
223			const dangerousElements = body.querySelectorAll(
224				'script:not([type^="math/"]), style, noscript, frame, frameset, object, embed, applet, base'
225			);
226			for (const el of dangerousElements) {
227				if (el.tagName === 'STYLE' && isSVGElement(el)) continue;
228				el.remove();
229			}
230	
231			// Remove event handler attributes, dangerous URIs, and srcdoc
232			const allElements = body.querySelectorAll('*');
233			for (const el of allElements) {
234				for (const attr of Array.from(el.attributes)) {
235					const name = attr.name.toLowerCase();
236					if (name.startsWith('on')) {
237						el.removeAttribute(attr.name);
238					} else if (name === 'srcdoc') {
239						el.removeAttribute(attr.name);
240					} else if (['href', 'src', 'action', 'formaction', 'xlink:href'].includes(name)) {
241						if (isDangerousUrl(attr.value)) {
242							el.removeAttribute(attr.name);
243						}
244					}
245				}
246			}
247		}
248	
249		/**
250		 * Replace base64 placeholder images with real URLs from <noscript> fallbacks.
251		 * Next.js (data-nimg) renders a tiny base64 gif as src with the real image
252		 * only inside a <noscript> sibling. This promotes the real URL before
253		 * noscript elements are stripped.
254		 */
255	
256		/**
257		 * Remove duplicate images within figures and adjacent elements, keeping
258		 * the highest resolution version. Handles Reader mode and lazy-loading
259		 * hydration creating a second copy alongside the original.
260		 */
261		private _deduplicateImages(body: Element): void {
262			for (const figure of body.querySelectorAll('figure')) {
263				const figImgs = Array.from(figure.querySelectorAll('img'))
264					.filter(img => !img.closest('noscript') && img.parentElement);
265				if (figImgs.length < 2) continue;
266	
267				// Group by alt text; empty-alt images share one group
268				const groups = new Map<string | null, Element[]>();
269				for (const img of figImgs) {
270					const src = img.getAttribute('src') || '';
271					if (!src || src.startsWith('data:')) continue;
272					const key = (img.getAttribute('alt') || '').trim() || null;
273					const group = groups.get(key) || [];
274					group.push(img);
275					groups.set(key, group);
276				}
277	
278				for (const [key, group] of groups) {
279					if (group.length < 2) continue;
280					// Same-src images with alt text are legitimate repeats, not dupes
281					if (key !== null && group.every(img => img.getAttribute('src') === group[0].getAttribute('src'))) continue;
282					this._keepBestImage(group);
283				}
284			}
285	
286			// Also deduplicate adjacent images outside figures (same alt, different src)
287			const imgs = Array.from(body.querySelectorAll('img'));
288			for (let i = 0; i < imgs.length; i++) {
289				const img = imgs[i];
290				if (img.closest('noscript') || img.closest('figure')) continue;
291				if (!img.parentElement) continue;
292	
293				const alt = (img.getAttribute('alt') || '').trim();
294				if (!alt) continue;
295				const src = img.getAttribute('src') || '';
296				if (!src || src.startsWith('data:')) continue;
297	
298				for (let j = i + 1; j < imgs.length; j++) {
299					const other = imgs[j];
300					if (other.closest('noscript') || other.closest('figure')) continue;
301					if (!other.parentElement) continue;
302	
303					const otherAlt = (other.getAttribute('alt') || '').trim();
304					if (otherAlt !== alt) break;
305					const otherSrc = other.getAttribute('src') || '';
306					if (!otherSrc || otherSrc.startsWith('data:')) continue;
307					if (otherSrc === src) break; // legitimate repeat
308	
309					this._keepBestImage([img, other]);
310					if (!img.parentElement) break; // img was the loser
311				}
312			}
313		}
314	
315		private _keepBestImage(group: Element[]): void {
316			let best = group[0];
317			for (let i = 1; i < group.length; i++) {
318				const winner = this._pickBestImage(best, group[i]);
319				(winner === best ? group[i] : best).remove();
320				best = winner;
321			}
322		}
323	
324		// Matches width hints in CDN image URLs:
325		//   imgproxy:    /width:1300/  or /w:1300/
326		//   Cloudinary:  /w_1300/ or ,w_1300,
327		//   Query param: ?w=1300 or &width=1300 or ?width=1300
328		//   Next.js:     ?w=1300
329		private static _urlWidthPattern = /(?:width[=:/]|[/,?&]w[_:=])(\d+)/;
330	
331		private _pickBestImage(a: Element, b: Element): Element {
332			// Tier 1: prefer images with srcset or inside <picture>
333			const tierA = a.getAttribute('srcset') ? 2 : a.closest('picture') ? 1 : 0;
334			const tierB = b.getAttribute('srcset') ? 2 : b.closest('picture') ? 1 : 0;
335			if (tierA !== tierB) return tierA > tierB ? a : b;
336	
337			// Tier 2: compare URL width hints within the same tier
338			const widthA = Defuddle._urlWidth(a);
339			const widthB = Defuddle._urlWidth(b);
340			if (widthA !== widthB) return widthA > widthB ? a : b;
341	
342			return a;
343		}
344	
345		private static _urlWidth(img: Element): number {
346			const src = img.getAttribute('src') || '';
347			const m = src.match(Defuddle._urlWidthPattern);
348			return m ? parseInt(m[1], 10) : 0;
349		}
350	
351		/**
352		 * Rename non-standard HTML attributes to their canonical lowercase forms.
353		 * React SSR outputs camelCase attributes like "srcSet" that some DOM
354		 * parsers (e.g. linkedom) preserve verbatim instead of lowercasing.
355		 */
356		private _normalizeAttributes(body: Element): void {
357			const renames: [string, string][] = [['srcSet', 'srcset']];
358			const elements = body.querySelectorAll('img, source');
359			for (const el of elements) {
360				for (const [from, to] of renames) {
361					const value = el.getAttribute(from);
362					if (value !== null) {
363						el.removeAttribute(from);
364						el.setAttribute(to, value);
365					}
366				}
367			}
368		}
369	
370		private _resolveNoscriptImages(body: Element): void {
371			const noscripts = body.querySelectorAll('noscript');
372			for (const noscript of noscripts) {
373				// Try direct child query first (linkedom parses noscript children).
374				// In browsers with JS enabled, noscript content is raw text:
375				// innerHTML is entity-encoded, textContent has the raw HTML.
376				let noscriptImg = noscript.querySelector('img');
377				if (!noscriptImg) {
378					let html = noscript.innerHTML || '';
379					if (!html.includes('<img')) {
380						html = noscript.textContent || '';
381					}
382					if (!html.includes('<img')) continue;
383					const fragment = parseHTML(this.doc, html);
384					noscriptImg = fragment.querySelector('img');
385				}
386				if (!noscriptImg) continue;
387	
388				const realSrc = noscriptImg.getAttribute('src') || '';
389				if (!realSrc || realSrc.startsWith('data:')) continue;
390	
391				const alt = noscriptImg.getAttribute('alt');
392				const parent = noscript.parentElement;
393				if (!parent) continue;
394	
395				let matched = false;
396				const siblingImgs = parent.querySelectorAll(':scope > img');
397				for (const img of siblingImgs) {
398					const src = img.getAttribute('src') || '';
399					if (!src.startsWith('data:')) continue;
400					// Match by alt text; require a non-empty alt to avoid false matches
401					if (!alt || img.getAttribute('alt') !== alt) continue;
402	
403					img.setAttribute('src', realSrc);
404					const srcset = noscriptImg.getAttribute('srcset') || '';
405					if (srcset) {
406						img.setAttribute('srcset', srcset);
407					}
408					matched = true;
409					break;
410				}
411	
412				// No matching sibling img — promote the noscript img directly.
413				// Only promote inside lazy-loading contexts (not tracking pixels)
414				// and only when no JS-hydrated image already exists.
415				// Exclude noscript children from the check — linkedom parses them
416				// as real elements.
417				if (!matched && this._isLazyImageContext(noscript)) {
418					const container = noscript.closest('figure') || parent;
419					const existingImgs = container.querySelectorAll('img');
420					let hasRealImage = false;
421					for (const img of existingImgs) {
422						if (img.closest('noscript')) continue;
423						const src = img.getAttribute('src') || '';
424						if (src && !src.startsWith('data:')) {
425							hasRealImage = true;
426							break;
427						}
428					}
429					if (!hasRealImage) {
430						const promotedImg = noscriptImg.cloneNode(true) as Element;
431						parent.insertBefore(promotedImg, noscript);
432					}
433				}
434			}
435		}
436	
437		/**
438		 * Detect whether a <noscript> is inside a lazy-loading image wrapper
439		 * (vs. a standalone tracking pixel that should not be promoted).
440		 */
441		private _isLazyImageContext(noscript: Element): boolean {
442			if (noscript.closest('figure')) return true;
443	
444			const parent = noscript.parentElement;
445			if (parent) {
446				for (const sibling of parent.children) {
447					if (sibling === noscript) continue;
448					if (getClassName(sibling).toLowerCase().includes('lazy')) return true;
449				}
450				const parentCls = getClassName(parent).toLowerCase();
451				if (parentCls.includes('image') || parentCls.includes('img') ||
452					parentCls.includes('picture') || parentCls.includes('photo') ||
453					parentCls.includes('media')) return true;
454			}
455	
456			return false;
457		}
458	
459		/**
460		 * Find the smallest DOM element whose text contains the search phrase
461		 * and whose word count is at least 80% of the expected count.
462		 * Shared by _findSchemaContentElement and _findContentBySchemaText.
463		 */
464		private _findElementBySchemaText(root: Element, schemaText: string): Element | null {
465			const firstPara = schemaText.split(/\n\s*\n/)[0]?.trim() || '';
466			const searchPhrase = firstPara.substring(0, 100).trim();
467			if (!searchPhrase) return null;
468	
469			const schemaWordCount = countWords(schemaText);
470			let bestMatch: Element | null = null;
471			let bestSize = Infinity;
472	
473			const allElements = root.querySelectorAll('*');
474			for (const el of allElements) {
475				if (el === root) continue;
476	
477				const elText = el.textContent || '';
478				if (!elText.includes(searchPhrase)) continue;
479	
480				const elWords = countWords(elText);
481				if (elWords >= schemaWordCount * 0.8 && elWords < bestSize) {
482					bestSize = elWords;
483					bestMatch = el;
484				}
485			}
486	
487			return bestMatch;
488		}
489	
490	
491		private findLargestHiddenContentSelector(): string | undefined {
492			const body = this.doc.body;
493			if (!body) return undefined;
494	
495			const candidates = Array.from(
496				body.querySelectorAll(HIDDEN_EXACT_SKIP_SELECTOR)
497			).filter(el => {
498				const className = el.getAttribute('class') || '';
499				return !className.includes('math');
500			});
501	
502			let best: Element | null = null;
503			let bestWords = 0;
504			for (const el of candidates) {
505				const words = countWords(el.textContent || '');
506				if (words > bestWords) {
507					best = el;
508					bestWords = words;
509				}
510			}
511	
512			if (!best || bestWords < 30) return undefined;
513			return this.getElementSelector(best);
514		}
515	
516		/**
517		 * Get the largest available src from an img element,
518		 * checking srcset for higher-resolution versions.
519		 */
520		private _getLargestImageSrc(img: Element): string {
521			const srcset = img.getAttribute('srcset') || '';
522			if (!srcset) return img.getAttribute('src') || '';
523	
524			// Parse srcset entries: each ends with a width descriptor (e.g. "424w")
525			// URLs may contain commas (e.g. Substack CDN), so split on width descriptors
526			const entryPattern = /(.+?)\s+(\d+(?:\.\d+)?)w/g;
527			let bestUrl = '';
528			let bestWidth = 0;
529			let match;
530			let lastIndex = 0;
531	
532			while ((match = entryPattern.exec(srcset)) !== null) {
533				let url = match[1].trim();
534				if (lastIndex > 0) {
535					url = url.replace(/^,\s*/, '');
536				}
537				lastIndex = entryPattern.lastIndex;
538	
539				const width = parseFloat(match[2]);
540				if (url && width > bestWidth) {
541					bestWidth = width;
542					bestUrl = url;
543				}
544			}
545	
546			let url = bestUrl || img.getAttribute('src') || '';
547	
548			// Strip CDN width/crop constraints to get the full resolution image
549			// (e.g. Cloudinary-style params: ,w_852,c_limit → removed)
550			url = url.replace(/,w_\d+/g, '').replace(/,c_\w+/g, '');
551	
552			return url;
553		}
554	
555		/**
556		 * Parse the document asynchronously. Checks for extractors that prefer
557		 * async (e.g. YouTube transcripts) before sync, then falls back to async
558		 * extractors if sync parse yields no content.
559		 */
560		async parseAsync(): Promise<DefuddleResponse> {
561			if (this.options.useAsync !== false) {
562				const asyncResult = await this.tryAsyncExtractor(
563					ExtractorRegistry.findPreferredAsyncExtractor.bind(ExtractorRegistry)
564				);
565				if (asyncResult) return asyncResult;
566			}
567	
568			const result = this.parse();
569	
570			if (result.wordCount > 0 || this.options.useAsync === false) {
571				return result;
572			}
573	
574			return (await this.tryAsyncExtractor(
575				ExtractorRegistry.findAsyncExtractor.bind(ExtractorRegistry)
576			)) ?? result;
577		}
578	
579		/**
580		 * Fetch only async variables (e.g. transcript) without re-parsing.
581		 * Safe to call after parse() — uses cached schema.org data since
582		 * parse() strips script tags from the document.
583		 */
584		async fetchAsyncVariables(): Promise<{ [key: string]: string } | null> {
585			if (this.options.useAsync === false) return null;
586	
587			try {
588				const url = this.options.url || this.doc.URL;
589				const schemaOrgData = this.getSchemaOrgData();
590				const extractorOpts: ExtractorOptions = { includeReplies: this.options.includeReplies ?? 'extractors', language: this.options.language, fetch: this.options.fetch };
591				const extractor = ExtractorRegistry.findPreferredAsyncExtractor(this.doc, url, schemaOrgData, extractorOpts);
592	
593				if (extractor) {
594					const extracted = await extractor.extractAsync();
595					return this.getExtractorVariables(extracted.variables) || null;
596				}
597			} catch (error) {
598				console.error('Defuddle', 'Error fetching async variables:', error);
599			}
