697				const extractorOpts: ExtractorOptions = {
698					includeReplies: options.includeReplies as ExtractorOptions['includeReplies'],
699					language: options.language,
700					fetch: options.fetch,
701				};
702				if (!this._inExtractorPipelineRun) {
703					const extractor = ExtractorRegistry.findExtractor(this.doc, url, schemaOrgData, extractorOpts);
