705						const extracted = extractor.extract();
706						if (extracted.contentSelector) {
707							this._inExtractorPipelineRun = true;
708							try {
709								const pipelineResult = this.parseInternal({
710									contentSelector: extracted.contentSelector,
711									removeLowScoring: false,
712									removeHiddenElements: false,
713								});
714								const variables = this.getExtractorVariables(extracted.variables);
715								return {
716									...pipelineResult,
717									title: extracted.variables?.title || pipelineResult.title,
718									description: extracted.variables?.description || pipelineResult.description,
719									author: extracted.variables?.author || pipelineResult.author,
720									published: extracted.variables?.published || pipelineResult.published,
721									site: extracted.variables?.site || pipelineResult.site,
722									language: extracted.variables?.language || pipelineResult.language,
723									extractorType: extractor.constructor.name.replace('Extractor', '').toLowerCase(),
