818					if (options.standardize) {
819						standardizeFootnotes(mainContent!);
820						standardizeCallouts(mainContent!);
821					}
822				});
823	
824				// Remove small images
825				profileStep('removeSmallImages', () => {
826					if (options.removeSmallImages) {
827						removeSmallImages(clone, smallImages, this.debug);
828					}
829				});
830	
831				// Remove hidden elements using computed styles
832				profileStep('removeHiddenElements', () => {
833					if (options.removeHiddenElements) {
834						removeHiddenElements(clone, this.debug, debugRemovals);
835					}
836				});
837	
838				// Remove clutter using selectors — deterministic removal of known
839				// non-content elements (nav, footer, .sidebar, etc.) by class/id.
840				// Runs before scoring so the heuristic scorer sees a cleaner DOM.
841				profileStep('removeBySelector', () => {
842					if (options.removeExactSelectors || options.removePartialSelectors) {
843						removeBySelector(
844							clone,
845							this.debug,
846							options.removeExactSelectors,
847							options.removePartialSelectors,
848							mainContent!,
849							debugRemovals,
850							options.removeHiddenElements === false
851						);
852					}
853				});
854	
855				// Remove non-content blocks by scoring — heuristic removal based
856				// on link density, text ratios, and navigation indicators.
857				profileStep('removeLowScoring', () => {
858					if (options.removeLowScoring) {
859						ContentScorer.scoreAndRemove(clone, this.debug, debugRemovals, mainContent!);
860					}
861				});
862	
863				// Remove elements by content patterns (read time, boilerplate, article cards)
864				profileStep('removeByContentPattern', () => {
