869				});
870	
871				// Normalize the main content
872				profileStep('standardizeContent', () => {
873					if (options.standardize) {
874						standardizeContent(mainContent!, metadata, this.doc, this.debug, doProfile ? profile : undefined);
875					}
876				});
877	
878				// Resolve relative URLs to absolute
879				profileStep('resolveRelativeUrls', () => this.resolveRelativeUrls(mainContent!));
880	
881				// Remove duplicate images (same alt, different resolution)
882				// after all image processing and URL resolution is complete
883				this._deduplicateImages(mainContent!);
884	
885				const content = mainContent.outerHTML;
886				const endTime = Date.now();
887	
888				const result: DefuddleResponse = {
889					content,
890					...metadata,
891					wordCount: this.countHtmlWords(content),
892					parseTime: Math.round(endTime - startTime),
893					metaTags: pageMetaTags
894				};
895	
896				if (this.debug) {
897					result.debug = {
898						contentSelector: this.getElementSelector(mainContent),
899						removals: debugRemovals
900					};
901				}
902	
903				if (this.options.profile) {
904					result.profile = profile;
905				}
906	
907				return result;
908			} catch (error) {
909				console.error('Defuddle', 'Error processing document:', error);
910				const errorContent = this.doc.body ? this.resolveContentUrls(serializeHTML(this.doc.body)) : '';
911				const endTime = Date.now();
912				return {
913					content: errorContent,
914					...metadata,
915					wordCount: this.countHtmlWords(errorContent),
916					parseTime: Math.round(endTime - startTime),
917					metaTags: pageMetaTags
918				};
919			}
920		}
