922		private countHtmlWords(content: string): number {
923			// Strip HTML tags and decode common entities without DOM parsing
924			const text = content
925				.replace(/<[^>]*>/g, ' ')
926				.replace(/&nbsp;/gi, ' ')
927				.replace(/&amp;/gi, '&')
928				.replace(/&lt;/gi, '<')
929				.replace(/&gt;/gi, '>')
930				.replace(/&quot;/gi, '"')
931				.replace(/&#\d+;/g, ' ')
932				.replace(/&\w+;/g, ' ');
933	
934			return countWords(text);
935		}
