943		private _evaluateMediaQueries(doc: Document): StyleChange[] {
944			const mobileStyles: StyleChange[] = [];
945			const maxWidthRegex = /max-width[^:]*:\s*(\d+)/;
946	
947			try {
948				if (!doc.styleSheets) return mobileStyles;
949	
950				// Get all styles, including inline styles
951				const sheets = Array.from(doc.styleSheets).filter(sheet => {
952					try {
953						// Access rules once to check validity
954						sheet.cssRules;
955						return true;
956					} catch (e) {
957						// Expected error for cross-origin stylesheets or Node.js environment
958						if (e instanceof DOMException && e.name === 'SecurityError') {
959							return false;
960						}
961						return false;
962					}
963				});
964				
965				// Process all sheets in a single pass
966				const mediaRules = sheets.flatMap(sheet => {
967					try {
968						// Check if we're in a browser environment where CSSMediaRule is available
969						if (typeof CSSMediaRule === 'undefined') {
970							return [];
971						}
972	
973						return Array.from(sheet.cssRules)
974							.filter((rule): rule is CSSMediaRule => 
975								rule instanceof CSSMediaRule &&
976								rule.conditionText.includes('max-width')
977							);
978					} catch (e) {
979						if (this.debug) {
980							console.warn('Defuddle: Failed to process stylesheet:', e);
981						}
982						return [];
983					}
984				});
985	
986				// Process all media rules in a single pass
987				mediaRules.forEach(rule => {
988					const match = rule.conditionText.match(maxWidthRegex);
989					if (match) {
990						const maxWidth = parseInt(match[1]);
991						
992						if (MOBILE_WIDTH <= maxWidth) {
993							// Batch process all style rules
994							const styleRules = Array.from(rule.cssRules)
995								.filter((r): r is CSSStyleRule => r instanceof CSSStyleRule);
996	
997							styleRules.forEach(cssRule => {
998								try {
999									mobileStyles.push({
1000										selector: cssRule.selectorText,
1001										styles: cssRule.style.cssText
1002									});
1003								} catch (e) {
1004									if (this.debug) {
1005										console.warn('Defuddle: Failed to process CSS rule:', e);
1006									}
1007								}
1008							});
1009						}
1010					}
1011				});
1012			} catch (e) {
1013				console.error('Defuddle: Error evaluating media queries:', e);
1014			}
1015	
1016			return mobileStyles;
1017		}
