1019		private applyMobileStyles(doc: Document, mobileStyles: StyleChange[]) {
1020			let appliedCount = 0;
1021	
1022			mobileStyles.forEach(({selector, styles}) => {
1023				try {
1024					const elements = doc.querySelectorAll(selector);
1025					elements.forEach(element => {
1026						element.setAttribute('style', 
1027							(element.getAttribute('style') || '') + styles
1028						);
1029						appliedCount++;
1030					});
1031				} catch (e) {
1032					console.error('Defuddle', 'Error applying styles for selector:', selector, e);
1033				}
1034			});
1035	
1036		}
