1045		private findMainContent(doc: Document): Element | null {
1046			// Find all potential content containers
1047			const candidates: { element: Element; score: number; selectorIndex: number }[] = [];
1048	
1049			ENTRY_POINT_ELEMENTS.forEach((selector, index) => {
1050				const elements = doc.querySelectorAll(selector);
1051				elements.forEach(element => {
1052					// Base score from selector priority (earlier = higher)
1053					let score = (ENTRY_POINT_ELEMENTS.length - index) * 40;
1054	
1055					// Add score based on content analysis
1056					score += ContentScorer.scoreElement(element);
1057	
1058					candidates.push({ element, score, selectorIndex: index });
1059				});
1060			});
1061	
1062			if (candidates.length === 0) {
1063				// Fall back to scoring block elements
1064				return this.findContentByScoring(doc);
1065			}
1066	
1067			// Sort by score descending
1068			candidates.sort((a, b) => b.score - a.score);
1069	
1070			if (this.debug) {
1071				this._log('Content candidates:', candidates.map(c => ({
1072					element: c.element.tagName,
1073					selector: this.getElementSelector(c.element),
1074					score: c.score
1075				})));
1076			}
1077	
1078			// If we only matched body, try table-based detection
1079			if (candidates.length === 1 && candidates[0].element.tagName.toLowerCase() === 'body') {
1080				const tableContent = this.findTableBasedContent(doc);
1081				if (tableContent) {
1082					return tableContent;
1083				}
1084			}
1085	
1086			// If the top candidate contains a child candidate that matched a
1087			// higher-priority selector, prefer the most specific (deepest) child.
1088			// This prevents e.g. <main> from winning over a contained <article>
1089			// just because sibling noise inflates the parent's content score.
1090			// Only prefer the child if it has meaningful content (>50 words),
1091			// otherwise it may be an empty card element (e.g. related article cards).
1092			// Skip this when the parent contains multiple children matching the
1093			// same selector — that indicates a listing/portfolio page where the
1094			// parent is the real content container.
1095			const top = candidates[0];
1096			let best = top;
1097			for (let i = 1; i < candidates.length; i++) {
1098				const child = candidates[i];
1099				const childWords = countWords(child.element.textContent || '');
1100				if (child.selectorIndex < best.selectorIndex && best.element.contains(child.element) && childWords > 50) {
1101					// Count how many candidates share this selector index inside
1102					// the top element. Use top (not best) as the stable reference
1103					// so the check isn't affected by earlier iterations.
1104					let siblingsAtIndex = 0;
1105					for (const c of candidates) {
1106						if (c.selectorIndex === child.selectorIndex && top.element.contains(c.element)) {
1107							if (++siblingsAtIndex > 1) break;
1108						}
1109					}
1110					if (siblingsAtIndex > 1) {
1111						// Multiple articles/cards inside the parent — it's a listing page
1112						continue;
1113					}
1114					best = child;
1115				}
1116			}
1117			if (best !== top) {
1118				return best.element;
1119			}
1120	
1121			return top.element;
1122		}
