1124		private findTableBasedContent(doc: Document): Element | null {
1125			// First check if this looks like an old-style table-based layout
1126			const tables = Array.from(doc.getElementsByTagName('table'));
1127			const hasTableLayout = tables.some(table => {
1128				const width = parseInt(table.getAttribute('width') || '0');
1129				const style = this.getComputedStyle(table);
1130				const tableClass = getClassName(table).toLowerCase();
1131				return width > 400 ||
1132					(style?.width?.includes('px') && parseInt(style.width) > 400) ||
1133					table.getAttribute('align') === 'center' ||
1134					tableClass.includes('content') ||
1135					tableClass.includes('article') ||
1136					// Multi-column layout: a row with 2+ cells where at least one has an explicit width
1137					Array.from(table.getElementsByTagName('tr')).some(row => {
1138						const cells = Array.from(row.children).filter(c => c.tagName === 'TD');
1139						return cells.length >= 2 && cells.some(c => c.getAttribute('width'));
1140					});
1141			});
1142	
1143			if (!hasTableLayout) {
1144				return null; // Don't try table-based extraction for modern layouts
1145			}
1146	
1147			const cells = Array.from(doc.getElementsByTagName('td'));
1148			return ContentScorer.findBestElement(cells);
1149		}
