1154			doc.querySelectorAll(BLOCK_ELEMENTS_SELECTOR).forEach((element: Element) => {
1155				const score = ContentScorer.scoreElement(element);
1156				if (score > 0) {
1157					candidates.push({ score, element });
1158				}
1159			});
1160	
1161			return candidates.length > 0 ? candidates.sort((a, b) => b.score - a.score)[0].element : null;
1162		}
