1164		private getElementSelector(element: Element): string {
1165			const parts: string[] = [];
1166			let current: Element | null = element;
1167			
1168			while (current && current !== this.doc.documentElement) {
1169				let selector = current.tagName.toLowerCase();
1170				if (current.id) {
1171					selector += '#' + current.id;
1172				} else if (getClassName(current)) {
1173					selector += '.' + getClassName(current).trim().split(/\s+/).join('.');
1174				}
1175				parts.unshift(selector);
1176				current = current.parentElement;
1177			}
1178			
1179			return parts.join(' > ');
1180		}
