1218				} catch {
1219					return normalized || url;
1220				}
1221			};
1222	
1223			element.querySelectorAll('[href]').forEach(el => {
1224				const href = el.getAttribute('href');
1225				if (href) el.setAttribute('href', resolve(href));
1226			});
1227	
1228			element.querySelectorAll('[src]').forEach(el => {
1229				const src = el.getAttribute('src');
1230				if (src) el.setAttribute('src', resolve(src));
1231			});
1232	
1233			element.querySelectorAll('[srcset]').forEach(el => {
1234				const srcset = el.getAttribute('srcset');
1235				if (srcset) {
1236					// Parse srcset using width/density descriptors as delimiters,
1237					// not commas — URLs may contain commas (e.g. CDN transform params)
1238					const entryPattern = /(.+?)\s+(\d+(?:\.\d+)?[wx])/g;
1239					const entries: string[] = [];
1240					let match;
1241					let lastIdx = 0;
1242	
1243					while ((match = entryPattern.exec(srcset)) !== null) {
1244						let url = match[1].trim();
1245						if (lastIdx > 0) {
1246							url = url.replace(/^,\s*/, '');
1247						}
1248						lastIdx = entryPattern.lastIndex;
1249						entries.push(`${resolve(url)} ${match[2]}`);
1250					}
1251	
1252					if (entries.length > 0) {
1253						el.setAttribute('srcset', entries.join(', '));
1254					} else {
1255						// Fallback: simple comma split for srcsets without descriptors
1256						const resolved = srcset.split(',').map(entry => {
1257							const parts = entry.trim().split(/\s+/);
1258							if (parts[0]) parts[0] = resolve(parts[0]);
1259							return parts.join(' ');
1260						}).join(', ');
1261						el.setAttribute('srcset', resolved);
1262					}
1263				}
1264			});
1265	
1266			element.querySelectorAll('[poster]').forEach(el => {
1267				const poster = el.getAttribute('poster');
1268				if (poster) el.setAttribute('poster', resolve(poster));
1269			});
1270		}
1271	
1272		/**
1273		 * Flatten shadow DOM content into a cloned document.
1274		 * Walks both trees in parallel so positional correspondence is exact.
1275		 */
1276		private flattenShadowRoots(original: Document, clone: Document): void {
1277			if (!original.body || !clone.body) return;
1278			const origElements = Array.from(original.body.querySelectorAll('*'));
1279	
1280			// Find the first element with a shadow root (also serves as the hasShadowRoots check)
1281			const firstShadow = origElements.find(el => el.shadowRoot);
1282			if (!firstShadow) return;
1283	
1284			const cloneElements = Array.from(clone.body.querySelectorAll('*'));
1285	
1286			// Check if we can directly read shadow DOM content (main world / Node.js).
1287			// In content script isolated worlds, shadowRoot exists but content is empty.
1288			const canReadShadow = (firstShadow.shadowRoot?.childNodes?.length ?? 0) > 0;
1289	
1290			if (canReadShadow) {
1291				// Direct traversal works (main world / Node.js)
1292				for (let i = origElements.length - 1; i >= 0; i--) {
1293					const origEl = origElements[i];
1294					if (!origEl.shadowRoot) continue;
1295	
1296					const cloneEl = cloneElements[i];
1297					if (!cloneEl) continue;
1298	
1299					const shadowHtml = origEl.shadowRoot.innerHTML;
1300					if (shadowHtml.length > 0) {
1301						this.replaceShadowHost(cloneEl, shadowHtml, clone);
1302					}
1303				}
1304			} else {
1305				// Content script isolated world — read data-defuddle-shadow attributes
1306				// stamped by an external main-world script.
1307				const shadowData: {cloneEl: Element, html: string}[] = [];
1308				for (let i = 0; i < origElements.length; i++) {
1309					const origEl = origElements[i];
1310					const shadowHtml = origEl.getAttribute('data-defuddle-shadow');
1311					if (!shadowHtml) continue;
1312	
1313					const cloneEl = cloneElements[i];
1314					if (!cloneEl) continue;
1315	
1316					shadowData.push({cloneEl, html: shadowHtml});
1317					// Clean up temporary attributes from both original and clone
1318					origEl.removeAttribute('data-defuddle-shadow');
1319					cloneEl.removeAttribute('data-defuddle-shadow');
1320				}
1321				for (const {cloneEl, html} of shadowData) {
1322					this.replaceShadowHost(cloneEl, html, clone);
1323				}
1324			}
1325		}
1326	
1327		/**
1328		 * Resolve React streaming SSR suspense boundaries.
1329		 * React's streaming SSR places content in hidden divs (id="S:0") and
1330		 * template placeholders (id="B:0") with $RC scripts to swap them.
1331		 * Since we don't execute scripts, we perform the swap manually.
1332		 */
1333		private resolveStreamedContent(doc: Document): void {
1334			// Find $RC("B:X","S:X") calls in inline scripts
1335			const scripts = doc.querySelectorAll('script');
1336			const swaps: { templateId: string; contentId: string }[] = [];
1337			const rcPattern = /\$RC\("(B:\d+)","(S:\d+)"\)/g;
1338	
1339			for (const script of scripts) {
1340				const text = script.textContent || '';
1341				if (!text.includes('$RC(')) continue;
1342				rcPattern.lastIndex = 0;
1343				let match;
1344				while ((match = rcPattern.exec(text)) !== null) {
1345					swaps.push({ templateId: match[1], contentId: match[2] });
1346				}
1347			}
1348	
1349			if (swaps.length === 0) return;
1350	
1351			let swapCount = 0;
1352			for (const { templateId, contentId } of swaps) {
1353				const template = doc.getElementById(templateId);
1354				const content = doc.getElementById(contentId);
1355				if (!template || !content) continue;
1356	
1357				const parent = template.parentNode;
1358				if (!parent) continue;
1359	
1360				// Remove the fallback/skeleton content after the template
1361				// until the <!--/$--> comment marker
1362				let next = template.nextSibling;
1363				let foundMarker = false;
1364				while (next) {
1365					const following = next.nextSibling;
1366					if (next.nodeType === 8 && (next as Comment).data === '/$') {
1367						next.remove();
1368						foundMarker = true;
1369						break;
1370					}
1371					next.remove();
1372					next = following;
1373				}
1374	
1375				// Skip swap if marker wasn't found — malformed streaming output
1376				if (!foundMarker) continue;
1377	
1378				// Insert content children before the template position
1379				while (content.firstChild) {
1380					parent.insertBefore(content.firstChild, template);
1381				}
1382	
1383				// Clean up the template and hidden div
1384				template.remove();
1385				content.remove();
1386				swapCount++;
1387			}
1388	
1389			if (swapCount > 0) {
1390				this._log('Resolved streamed content:', swapCount, 'suspense boundaries');
1391			}
1392		}
1393	
1394		/**
1395		 * Replace a shadow DOM host element with a div containing its shadow content.
1396		 * Custom elements (tag names with hyphens) would re-initialize when inserted
1397		 * into a live DOM, recreating their shadow roots and hiding the content.
1398		 */
1399		private replaceShadowHost(el: Element, shadowHtml: string, doc: Document): void {
1400			const fragment = parseHTML(doc, shadowHtml);
1401			if (el.tagName.includes('-')) {
1402				// Custom element — replace with a div to prevent re-initialization
1403				const div = doc.createElement('div');
1404				div.appendChild(fragment);
1405				el.parentNode?.replaceChild(div, el);
1406			} else {
1407				el.textContent = '';
1408				el.appendChild(fragment);
1409			}
1410		}
1411	
1412		/**
1413		 * Resolve relative URLs in an HTML string
1414		 */
1415		private resolveContentUrls(html: string): string {
1416			const baseUrl = this.options.url || this.doc.URL;
1417			if (!baseUrl) return html;
1418	
1419			const container = this.doc.createElement('div');
1420			container.appendChild(parseHTML(this.doc, html));
1421			this.resolveRelativeUrls(container);
1422			return serializeHTML(container);
1423		}
1424	
1425		private _extractSchemaOrgData(doc: Document): any {
1426			const schemaScripts = doc.querySelectorAll('script[type="application/ld+json"]');
1427			const rawSchemaItems: any[] = [];
1428	
1429			schemaScripts.forEach(script => {
1430				let jsonContent = script.textContent || '';
1431				
1432				try {
1433					jsonContent = jsonContent
1434						.replace(/\/\*[\s\S]*?\*\/|^\s*\/\/.*$/gm, '')
1435						.replace(/^\s*<!\[CDATA\[([\s\S]*?)\]\]>\s*$/, '$1')
1436						.replace(/^\s*(\*\/|\/\*)\s*|\s*(\*\/|\/\*)\s*$/g, '')
1437						.trim();
1438						
1439					const jsonData = JSON.parse(jsonContent);
1440	
1441					if (jsonData['@graph'] && Array.isArray(jsonData['@graph'])) {
1442						rawSchemaItems.push(...jsonData['@graph']);
1443					} else {
1444						rawSchemaItems.push(jsonData);
1445					}
1446				} catch (error) {
1447					console.error('Defuddle: Error parsing schema.org data:', error);
1448					if (this.debug) {
1449						console.error('Defuddle: Problematic JSON content:', jsonContent);
1450					}
1451				}
1452			});
1453	
1454			const decodeStringsInObject = (item: any): any => {
1455				if (typeof item === 'string') {
1456					return this._decodeHTMLEntities(item);
1457				} else if (Array.isArray(item)) {
1458					return item.map(decodeStringsInObject);
1459				} else if (typeof item === 'object' && item !== null) {
1460					const newItem: { [key: string]: any } = {};
1461					for (const key in item) {
1462						if (Object.prototype.hasOwnProperty.call(item, key)) {
1463							newItem[key] = decodeStringsInObject(item[key]);
1464						}
1465					}
1466					return newItem;
1467				}
1468				return item;
1469			};
1470	
1471			return rawSchemaItems.map(decodeStringsInObject);
1472		}
1473	
1474		private _collectMetaTags(): MetaTagItem[] {
1475			const pageMetaTags: MetaTagItem[] = [];
1476			this.doc.querySelectorAll('meta').forEach(meta => {
1477				const name = meta.getAttribute('name');
1478				const property = meta.getAttribute('property');
1479				let content = meta.getAttribute('content');
1480				if (content) {
1481					pageMetaTags.push({ name, property, content: this._decodeHTMLEntities(content) });
1482				}
1483			});
1484			return pageMetaTags;
1485		}
1486	
1487		private _decodeHTMLEntities(text: string): string {
1488			return decodeHTMLEntities(this.doc, text);
1489		}
1490	
1491		/**
1492		 * Build a DefuddleResponse from an extractor result with metadata
1493		 */
1494		private buildExtractorResponse(
1495			extracted: { contentHtml: string; variables?: { [key: string]: string } },
1496			metadata: ReturnType<typeof MetadataExtractor.extract>,
1497			startTime: number,
1498			extractor: BaseExtractor,
1499			pageMetaTags: MetaTagItem[]
1500		): DefuddleResponse {
1501			const contentHtml = this.resolveContentUrls(extracted.contentHtml);
1502			const variables = this.getExtractorVariables(extracted.variables);
1503			return {
1504				content: contentHtml,
1505				title: extracted.variables?.title || metadata.title,
1506				description: extracted.variables?.description || metadata.description,
1507				domain: metadata.domain,
1508				favicon: metadata.favicon,
1509				image: metadata.image,
1510				language: extracted.variables?.language || metadata.language,
1511				published: extracted.variables?.published || metadata.published,
1512				author: extracted.variables?.author || metadata.author,
1513				site: extracted.variables?.site || metadata.site,
1514				schemaOrgData: metadata.schemaOrgData,
1515				wordCount: this.countHtmlWords(extracted.contentHtml),
1516				parseTime: Math.round(Date.now() - startTime),
1517				extractorType: extractor.constructor.name.replace('Extractor', '').toLowerCase(),
1518				metaTags: pageMetaTags,
1519				...(variables ? { variables } : {}),
1520			};
1521		}
1522	
1523		/**
1524		 * Filter extractor variables to only include custom ones
1525		 * (exclude standard fields that are already mapped to top-level properties)
1526		 */
1527		private getExtractorVariables(variables?: { [key: string]: string }): { [key: string]: string } | undefined {
1528			if (!variables) return undefined;
1529			const custom: { [key: string]: string } = {};
1530			let hasCustom = false;
1531			for (const [key, value] of Object.entries(variables)) {
1532				if (!STANDARD_VARIABLE_KEYS.has(key)) {
1533					custom[key] = value;
1534					hasCustom = true;
1535				}
1536			}
1537			return hasCustom ? custom : undefined;
1538		}
1539	
1540	}
