187			score -= nestedTables * 5;
188	
189			// Additional scoring for table cells
190			if (element.tagName.toLowerCase() === 'td') {
191				// Table cells get a bonus for being in the main content area
192				const parentTable = element.closest('table');
193				if (parentTable) {
194					// Only favor cells in tables that look like old-style content layouts
195					const tableWidth = parseInt(parentTable.getAttribute('width') || '0');
196					const tableAlign = parentTable.getAttribute('align') || '';
197					const tableClass = getClassName(parentTable).toLowerCase();
198					const isTableLayout = 
199						tableWidth > 400 || // Common width for main content tables
200						tableAlign === 'center' ||
201						tableClass.includes('content') ||
202						tableClass.includes('article');
203	
204					if (isTableLayout) {
