420		 * Scores a block element based on various criteria to determine if it's likely not content.
421		 * Returns a negative score if the element is likely not content, a positive score if it is.
422		 */
423		private static scoreNonContentBlock(element: Element): number {
424			// Skip footnote list elements and their descendants
425			try {
426				if (element.matches(FOOTNOTE_LIST_SELECTORS) ||
427					element.querySelector(FOOTNOTE_LIST_SELECTORS) ||
428					element.closest(FOOTNOTE_LIST_SELECTORS)) {
429					return 0;
430				}
431			} catch (e) {}
