433			let score = 0;
434	
435			// Get text content
436			const text = element.textContent || '';
437			const words = countWords(text);
438	
439			// Skip very small elements
440			if (words < 3) {
441				return 0;
442			}
443	
444			// Comma counting — prose has commas, navigation/boilerplate doesn't.
445			// This counterbalances negative signals from navigation indicators.
446			const commas = text.split(/,/).length - 1;
447			score += commas;
448	
449			const textLower = text.toLowerCase();
450			let indicatorMatches = 0;
451			for (const regex of navigationIndicatorRegexes) {
452				if (regex.test(textLower)) {
453					indicatorMatches++;
454				}
455			}
456			score -= indicatorMatches * 10;
457	
458			// Check for high link density (navigation)
459			const linkElements = element.getElementsByTagName('a');
460			const links = linkElements.length;
461			const linkDensity = links / (words || 1);
462			if (linkDensity > 0.5) {
463				score -= 15;
464			}
465	
466			// Check for high link text ratio (e.g. card groups, nav sections)
467			// Requires multiple links to avoid penalizing content paragraphs
468			// that happen to be wrapped in a single link
469			if (links > 1 && words < 80) {
470				let linkTextLength = 0;
471				for (let i = 0; i < linkElements.length; i++) {
472					linkTextLength += (linkElements[i].textContent || '').length;
473				}
474				const totalTextLength = text.length;
475				if (totalTextLength > 0 && linkTextLength / totalTextLength > 0.8) {
476					score -= 15;
477				}
478			}
479	
480			// Check for list structure (navigation)
481			const lists = element.getElementsByTagName('ul').length + element.getElementsByTagName('ol').length;
482			if (lists > 0 && links > lists * 3) {
483				score -= 10;
484			}
485	
486			// Check for social media profile links (author bios, social widgets)
487			if (words < 80) {
488				const elLinks = element.getElementsByTagName('a');
489				for (let i = 0; i < elLinks.length; i++) {
490					const href = (elLinks[i].getAttribute('href') || '').toLowerCase();
491					if (socialProfilePattern.test(href)) {
492						score -= 15;
493						break;
494					}
495				}
496			}
497	
498			// Penalize very small blocks that look like standalone author bylines with dates
499			// e.g. "By Author Name · March 4, 2026". Requires both an author attribution
500			// and a date to avoid false positives.
501			if (words < 15) {
502				if (bylinePattern.test(text) && datePattern.test(text)) {
503					score -= 10;
504				}
505			}
506	
507			// Penalize blocks that look like article card grids
508			if (ContentScorer.isCardGrid(element, words)) {
509				score -= 15;
510			}
511	
512			// Check for specific class patterns that indicate non-content
513			const className = getClassName(element).toLowerCase();
514			const id = element.id.toLowerCase();
515	
516			for (const pattern of nonContentPatterns) {
517				if (className.includes(pattern) || id.includes(pattern)) {
518					score -= 8;
519				}
520			}
521	
522			return score;
523		}
