528		 */
529		private static isCardGrid(element: Element, words: number): boolean {
530			if (words < 3 || words >= 500) return false;
531			const headings = element.querySelectorAll('h2, h3, h4');
532			if (headings.length < 3) return false;
533			const images = element.querySelectorAll('img');
