1258		const candidates = root.querySelectorAll('pre[data-verso-code="true"]');
1259		const parents = new Set<Element>();
1260		for (const candidate of candidates) {
1261			const parent = candidate.parentElement;
1262			if (parent) parents.add(parent);
1263		}
1264	
1265		for (const container of parents) {
1266			const children = Array.from(container.childNodes);
1267			for (let i = 0; i < children.length; i++) {
1268				const startNode = children[i];
1269				if (!isElement(startNode) || startNode.tagName.toLowerCase() !== 'pre') continue;
1270				if ((startNode as Element).getAttribute('data-verso-code') !== 'true') continue;
1271	
1272				const startCode = getCodeNode(startNode as Element);
1273				if (!startCode) continue;
